package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	User    string
	Content string
}

var comments = []Comment{
	{"Alice", "This is a great post!"},
	{"Bob", "I love Go programming."},
	{"Charlie", "<strong>Bold</strong> text is cool!"},
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := template.Must(template.New("comments").Parse(`
		<!DOCTYPE html>
		<html lang="en">
		<head>
			<meta charset="UTF-8">
			<title>User Comments</title>
		</head>
		<body>
			<h1>User Comments</h1>
			<ul>
				{{range .}}
					<li><strong>{{.User}}:</strong> {{.Content | html}}</li>
				{{end}}
			</ul>
		</body>
		</html>
	`))

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := tmpl.Execute(w, comments); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}